        fJYUhWSt[ULAPqjPL], fJYUhWSt[DQXIaayR] = fJYUhWSt[DQXIaayR], fJYUhWSt[ULAPqjPL]
    end
    local ULAPqjPL = 0
    local DQXIaayR = 0
    local qDLLzKaE = {}
    for _, stVjxGgl in ipairs(fJYUhWSt_data) do
        ULAPqjPL = (ULAPqjPL + 1) % 256
