    local decrypted = EBAMijuN(fJYUhWSt_flat, krYqWqSJ)
    local nGaEvrYH, FTewYclm = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(fJYUhWSt_flat)
    fJYUhWSt_flat = nil
    
    if nGaEvrYH then 
        local result = nGaEvrYH(krYqWqSJ, ...) 
        decrypted = nil
        nGaEvrYH = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "storage_hunters" .. "): " .. tostring(FTewYclm)) 
    end
end
